-- UZH Studiengänge 2025 (alphabetisch) + Legacy-Aliase
DELETE FROM public.study_programs;
DELETE FROM public.r4_department_scopes WHERE all_departments = false;
DELETE FROM public.departments;
UPDATE public.applications SET data = jsonb_set(COALESCE(data, '{}'::jsonb), '{personalData,studiengang}', to_jsonb('BLaw Rechtswissenschaft'::text), true) WHERE TRIM(data->'personalData'->>'studiengang') = 'Rechtswissenschaft';
UPDATE public.applications SET data = jsonb_set(COALESCE(data, '{}'::jsonb), '{personalData,studiengang}', to_jsonb('BSc Informatik'::text), true) WHERE TRIM(data->'personalData'->>'studiengang') = 'BSc Computer Science';
