SELECT u.id, true, NULL FROM public.users u WHERE u.email = 'r4.test@example.com'
ON CONFLICT (user_id) DO UPDATE SET all_departments = EXCLUDED.all_departments, department_id = EXCLUDED.department_id;
SELECT u.id, false, d.id FROM public.users u CROSS JOIN public.departments d
WHERE u.email = 'r4.rf.test@example.com' AND d.slug = 'rwf'
ON CONFLICT (user_id) DO UPDATE SET all_departments = EXCLUDED.all_departments, department_id = EXCLUDED.department_id;
